BEGIN;
CREATE TEMP TABLE ups_smoke_results(test_group text,test_name text,test_status text CHECK(test_status IN('PASS','WARN','FAIL')),severity text CHECK(severity IN('LOW','MEDIUM','HIGH','CRITICAL')),message text,created_at timestamptz DEFAULT now()) ON COMMIT PRESERVE ROWS;
DO $$ DECLARE v_error text; v_exception text; v_score numeric; BEGIN SELECT arb.ups_error_severity('10004',500) INTO v_error; INSERT INTO ups_smoke_results VALUES('FUNCTION_EXEC','ups_error_severity_transient',CASE WHEN v_error='TRANSIENT' THEN 'PASS' ELSE 'FAIL' END,'CRITICAL','severity='||coalesce(v_error,'null'),now()); SELECT arb.ups_delivery_exception_code(null,'Package was delivered') INTO v_exception; INSERT INTO ups_smoke_results VALUES('FUNCTION_EXEC','ups_delivery_exception_code',CASE WHEN v_exception='DELIVERED' THEN 'PASS' ELSE 'FAIL' END,'HIGH','exception='||coalesce(v_exception,'null'),now()); SELECT arb.ups_score_rate_option(10,8,20,3) INTO v_score; INSERT INTO ups_smoke_results VALUES('FUNCTION_EXEC','ups_score_rate_option',CASE WHEN v_score BETWEEN 0 AND 100 THEN 'PASS' ELSE 'FAIL' END,'HIGH','score='||coalesce(v_score::text,'null'),now()); END $$;
DO $$ DECLARE r record; BEGIN FOR r IN SELECT * FROM (VALUES ('ups_address_validation_events'),('ups_rate_quote_events'),('ups_shipment_label_events'),('ups_tracking_snapshots'),('ups_tracking_webhook_events'),('ups_decision_events')) t(table_name) LOOP BEGIN EXECUTE format('SELECT count(*) FROM arb.%I',r.table_name); INSERT INTO ups_smoke_results VALUES('QUERYABILITY','count:'||r.table_name,'PASS','HIGH','Count query succeeded.',now()); EXCEPTION WHEN OTHERS THEN INSERT INTO ups_smoke_results VALUES('QUERYABILITY','count:'||r.table_name,'FAIL','HIGH',SQLERRM,now()); END; END LOOP; END $$;
SELECT count(*) total_checks,count(*) FILTER(WHERE test_status='PASS') pass_count,count(*) FILTER(WHERE test_status='WARN') warn_count,count(*) FILTER(WHERE test_status='FAIL') fail_count FROM ups_smoke_results;
SELECT * FROM ups_smoke_results WHERE test_status<>'PASS' ORDER BY severity,test_group,test_name;
DO $$ DECLARE fail_count int; BEGIN SELECT count(*) INTO fail_count FROM ups_smoke_results WHERE test_status='FAIL'; IF fail_count>0 THEN RAISE EXCEPTION 'UPS Green Tier 1 smoke failed with % failures',fail_count; END IF; END $$;
COMMIT;
